fn main() -> i64 = {
    let capacity = read_int();
    let n = read_int();

    // Ring buffer implementation using vec
    // We use a fixed-size vec for the buffer, and head/tail pointers
    // Since BMB vecs are dynamic, we'll pre-allocate and use indices
    let buf = vec_new();
    let _i = 0;
    while _i < capacity {
        let _p = vec_push(buf, 0);
        _i += 1
    };

    let mut head = 0;
    let mut tail = 0;
    let mut count = 0;

    let _op_i = 0;
    while _op_i < n {
        let op = read_int();
        if op == 1 {
            let val = read_int();
            if count < capacity {
                let _s = vec_set(buf, tail, val);
                tail = (tail + 1) % capacity;
                count = count + 1
            }
            // if full, discard (do nothing)
        } else if op == 2 {
            if count > 0 {
                let val = vec_get(buf, head);
                let _p = println(val);
                head = (head + 1) % capacity;
                count = count - 1
            } else {
                let _p = println(-1)
            }
        } else if op == 3 {
            let _p = println(count)
        };
        _op_i += 1
    };

    let _f = vec_free(buf);
    0
};

